package com.example.kotlinapppractise

import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import com.example.kotlinapppractise.ui.theme.KotlinAppPractiseTheme

class MainActivity : ComponentActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        Log.d("Lifecycle", "onCreate called")
        setContent {
            KotlinAppPractiseTheme {
                Scaffold(modifier = Modifier.fillMaxSize()) { innerPadding ->
                    MainScreen(modifier = Modifier.padding(innerPadding))
                }
            }
        }
    }


    override fun onStart() {
        super.onStart()
        Log.d("Lifecycle", "onStart called")
    }

    override fun onResume() {
        super.onResume()
        Log.d("Lifecycle", "onResume called")
    }

    override fun onPause() {
        super.onPause()
        Log.d("Lifecycle", "onPause called")
    }

    override fun onStop() {
        super.onStop()
        Log.d("Lifecycle", "onStop called")
    }

    override fun onDestroy() {
        super.onDestroy()
        Log.d("Lifecycle", "onDestroy called")
    }
}

private const val MAX_INPUT_LENGTH = 50

@Composable
fun MainScreen(modifier: Modifier = Modifier) {
    var inputText by remember { mutableStateOf("") }
    var itemList by remember { mutableStateOf(listOf<String>()) }
    var errorMessage by remember { mutableStateOf<String?>(null) }
    var searchQuery by remember { mutableStateOf("") }
    var isSorted by remember { mutableStateOf(false) }

    // Derived list: filter by search, then optionally sort
    val displayedList = remember(itemList, searchQuery, isSorted) {
        try {
            val filtered = if (searchQuery.isBlank()) itemList
                           else itemList.filter { it.contains(searchQuery, ignoreCase = true) }
            val result = if (isSorted) filtered.sorted() else filtered
            Log.d("MainScreen", "displayedList updated: total=${itemList.size}, shown=${result.size}, sorted=$isSorted, query=\"$searchQuery\"")
            result
        } catch (e: Exception) {
            Log.e("MainScreen", "Error computing displayedList", e)
            itemList
        }
    }

    Column(
        modifier = modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {
        OutlinedTextField(
            value = inputText,
            onValueChange = {
                try {
                    if (it.length <= MAX_INPUT_LENGTH) {
                        inputText = it
                        errorMessage = null
                        Log.d("MainScreen", "Input changed: length=${it.length}/$MAX_INPUT_LENGTH")
                    } else {
                        errorMessage = "Maximum $MAX_INPUT_LENGTH characters allowed"
                        Log.w("MainScreen", "Input exceeds max length: ${it.length}/$MAX_INPUT_LENGTH")
                    }
                } catch (e: Exception) {
                    Log.e("MainScreen", "Error handling input change", e)
                }
            },
            label = { Text("Enter something") },
            isError = errorMessage != null,
            supportingText = {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    Text(
                        text = errorMessage ?: "",
                        color = if (errorMessage != null) MaterialTheme.colorScheme.error
                                else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                    Text(
                        text = "${inputText.length}/$MAX_INPUT_LENGTH",
                        color = if (errorMessage != null) MaterialTheme.colorScheme.error
                                else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            },
            modifier = Modifier.fillMaxWidth()
        )

        Button(
            onClick = {
                try {
                    when {
                        inputText.isBlank() -> {
                            errorMessage = "Input cannot be empty"
                            Log.w("MainScreen", "Add attempted but input was blank")
                        }
                        inputText.length > MAX_INPUT_LENGTH -> {
                            errorMessage = "Maximum $MAX_INPUT_LENGTH characters allowed"
                            Log.w("MainScreen", "Add attempted but input exceeds max length: ${inputText.length}/$MAX_INPUT_LENGTH")
                        }
                        itemList.any { it.equals(inputText.trim(), ignoreCase = true) } -> {
                            errorMessage = "\"${inputText.trim()}\" already exists in the list"
                            Log.w("MainScreen", "Duplicate item attempted: \"${inputText.trim()}\"")
                        }
                        else -> {
                            itemList = itemList + inputText.trim()
                            Log.d("MainScreen", "Item added: $inputText | Total items: ${itemList.size}")
                            inputText = ""
                            errorMessage = null
                        }
                    }
                } catch (e: Exception) {
                    Log.e("MainScreen", "Error adding item", e)
                }
            },
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Add to list")
        }

        OutlinedButton(
            onClick = {
                try {
                    val clearedCount = itemList.size
                    itemList = emptyList()
                    searchQuery = ""
                    Log.d("MainScreen", "List cleared | $clearedCount items removed")
                } catch (e: Exception) {
                    Log.e("MainScreen", "Error clearing list", e)
                }
            },
            modifier = Modifier.fillMaxWidth(),
            enabled = itemList.isNotEmpty()
        ) {
            Text("Clear All")
        }

        // ── Item count + Sort toggle ──────────────────────────────────────
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = if (searchQuery.isBlank()) "Items: ${itemList.size}"
                       else "Items: ${itemList.size}  (${displayedList.size} shown)",
                style = MaterialTheme.typography.bodySmall
            )
            TextButton(
                onClick = {
                    try {
                        isSorted = !isSorted
                        Log.d("MainScreen", "Sort toggled: isSorted=$isSorted")
                    } catch (e: Exception) {
                        Log.e("MainScreen", "Error toggling sort", e)
                    }
                },
                enabled = itemList.isNotEmpty()
            ) {
                Text(if (isSorted) "Sorted ✓" else "Sort A–Z")
            }
        }

        // ── Search / Filter ───────────────────────────────────────────────
        OutlinedTextField(
            value = searchQuery,
            onValueChange = {
                try {
                    searchQuery = it
                    Log.d("MainScreen", "Search query changed: \"$it\"")
                } catch (e: Exception) {
                    Log.e("MainScreen", "Error updating search query", e)
                }
            },
            label = { Text("Search list") },
            singleLine = true,
            modifier = Modifier.fillMaxWidth(),
            enabled = itemList.isNotEmpty()
        )

        // ── List ──────────────────────────────────────────────────────────
        LazyColumn(
            modifier = Modifier.fillMaxWidth(),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(displayedList) { item ->
                Card(modifier = Modifier.fillMaxWidth()) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(12.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(text = item)
                        TextButton(onClick = {
                            try {
                                itemList = itemList.filter { it != item }
                                Log.d("MainScreen", "Item deleted: $item | Remaining items: ${itemList.size}")
                            } catch (e: Exception) {
                                Log.e("MainScreen", "Error deleting item: $item", e)
                            }
                        }) {
                            Text("X")
                        }
                    }
                }
            }
        }
    }
}

package com.example.kotlinapppractise

import android.os.Bundle
import android.util.Log
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.activity.enableEdgeToEdge
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.viewmodel.compose.viewModel
import com.example.kotlinapppractise.ui.theme.KotlinAppPractiseTheme
import com.example.kotlinapppractise.viewmodel.MainViewModel

/**
 * ─────────────────────────────────────────────
 *  LAYER 3 — UI  (Screen / "Fragment" Layer)
 * ─────────────────────────────────────────────
 *
 * Architecture recap:
 *
 *   ┌─────────────────────────────────────────┐
 *   │  MainActivity / MainScreen  (UI Layer)   │  ← You are here
 *   │  • Renders state from ViewModel          │
 *   │  • Sends user events → ViewModel         │
 *   └──────────────────┬──────────────────────┘
 *                      │ calls fun / reads uiState
 *   ┌──────────────────▼──────────────────────┐
 *   │  MainViewModel  (Business Logic Layer)   │
 *   │  • Validates input                       │
 *   │  • Manages UI state (survives rotation)  │
 *   │  • Delegates data ops → Repository       │
 *   └──────────────────┬──────────────────────┘
 *                      │ add / remove / clear / get
 *   ┌──────────────────▼──────────────────────┐
 *   │  ItemRepository  (Data Layer)            │
 *   │  • Single source of truth                │
 *   │  • In-memory list (could be Room/API)    │
 *   └─────────────────────────────────────────┘
 *
 * Why split these layers?
 *   ✔ Each layer has ONE responsibility → easier to test
 *   ✔ ViewModel survives rotation → no data loss
 *   ✔ Repository can be swapped (e.g., Room DB) without touching UI
 */
class MainActivity : ComponentActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        Log.d("Lifecycle", "onCreate called")
        setContent {
            KotlinAppPractiseTheme {
                Scaffold(modifier = Modifier.fillMaxSize()) { innerPadding ->
                    // viewModel() is a Compose helper that:
                    //   • Creates MainViewModel the first time
                    //   • Returns the SAME instance on every recomposition & rotation
                    val vm: MainViewModel = viewModel()
                    MainScreen(
                        modifier = Modifier.padding(innerPadding),
                        viewModel = vm
                    )
                }
            }
        }
    }

    override fun onStart()   { super.onStart();   Log.d("Lifecycle", "onStart called") }
    override fun onResume()  { super.onResume();  Log.d("Lifecycle", "onResume called") }
    override fun onPause()   { super.onPause();   Log.d("Lifecycle", "onPause called") }
    override fun onStop()    { super.onStop();    Log.d("Lifecycle", "onStop called") }
    override fun onDestroy() { super.onDestroy(); Log.d("Lifecycle", "onDestroy called") }
}

// ─────────────────────────────────────────────────────────────────────────────
//  MainScreen — UI Layer
//  Reads from viewModel.uiState and sends events back via viewModel.xxx()
// ─────────────────────────────────────────────────────────────────────────────
@Composable
fun MainScreen(
    modifier: Modifier = Modifier,
    viewModel: MainViewModel          // injected from MainActivity
) {
    // Reading uiState here makes this Composable recompose whenever it changes.
    // The ViewModel owns the state; the UI just observes and renders it.
    val state = viewModel.uiState

    Column(
        modifier = modifier
            .fillMaxSize()
            .padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(12.dp)
    ) {

        // ── Architecture label ────────────────────────────────────────────
        Text(
            text = "UI Screen → ViewModel → Repository",
            style = MaterialTheme.typography.labelSmall,
            color = MaterialTheme.colorScheme.primary
        )

        HorizontalDivider()

        // ── Input field with validation + character counter ───────────────
        OutlinedTextField(
            value = state.inputText,
            onValueChange = { viewModel.onInputChanged(it) },   // event → VM
            label = { Text("Enter something") },
            isError = state.errorMessage != null,
            supportingText = {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween
                ) {
                    // Error message (left side)
                    Text(
                        text = state.errorMessage ?: "",
                        color = if (state.errorMessage != null)
                                    MaterialTheme.colorScheme.error
                                else
                                    MaterialTheme.colorScheme.onSurfaceVariant
                    )
                    // Character counter (right side)
                    Text(
                        text = "${state.inputText.length}/50",
                        color = if (state.errorMessage != null)
                                    MaterialTheme.colorScheme.error
                                else
                                    MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            },
            modifier = Modifier.fillMaxWidth()
        )

        // ── Add button ────────────────────────────────────────────────────
        Button(
            onClick = { viewModel.addItem() },          // event → VM → Repository
            modifier = Modifier.fillMaxWidth()
        ) {
            Text("Add to list")
        }

        // ── Clear button ──────────────────────────────────────────────────
        OutlinedButton(
            onClick = { viewModel.clearItems() },       // event → VM → Repository
            modifier = Modifier.fillMaxWidth(),
            enabled = state.items.isNotEmpty()
        ) {
            Text("Clear All")
        }

        // ── Item count + Sort toggle ──────────────────────────────────────
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceBetween,
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = if (state.searchQuery.isBlank())
                           "Items: ${state.items.size}"
                       else
                           "Items: ${state.items.size}  (${state.displayedList.size} shown)",
                style = MaterialTheme.typography.bodySmall
            )
            TextButton(
                onClick = { viewModel.toggleSort() },   // event → VM
                enabled = state.items.isNotEmpty()
            ) {
                Text(if (state.isSorted) "Sorted ✓" else "Sort A–Z")
            }
        }

        // ── Search / Filter ───────────────────────────────────────────────
        OutlinedTextField(
            value = state.searchQuery,
            onValueChange = { viewModel.onSearchChanged(it) },  // event → VM
            label = { Text("Search list") },
            singleLine = true,
            modifier = Modifier.fillMaxWidth(),
            enabled = state.items.isNotEmpty()
        )

        // ── List (filtered + sorted by ViewModel) ─────────────────────────
        // The UI just renders whatever displayedList the ViewModel computed.
        LazyColumn(
            modifier = Modifier.fillMaxWidth(),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            items(state.displayedList) { item ->
                Card(modifier = Modifier.fillMaxWidth()) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(12.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Text(text = item)
                        TextButton(
                            onClick = { viewModel.removeItem(item) }    // event → VM → Repository
                        ) {
                            Text("X")
                        }
                    }
                }
            }
        }
    }
}

package com.example.kotlinapppractise.data

import android.util.Log

/**
 * ─────────────────────────────────────────────
 *  LAYER 1 — REPOSITORY  (Data Layer)
 * ─────────────────────────────────────────────
 *
 * The Repository is the single source of truth for data.
 * It abstracts where data comes from (memory, database, network, etc.)
 * so that the ViewModel never needs to know the details.
 *
 * In a real app this would talk to:
 *   • Room database  → local persistence
 *   • Retrofit API   → remote server
 *   • DataStore      → preferences
 *
 * For this learning demo everything is kept in-memory.
 */
class ItemRepository {

    companion object {
        private const val TAG = "ItemRepository"
    }

    // Internal mutable list — only this class can modify it
    private val _items = mutableListOf<String>()

    // ── Read ──────────────────────────────────────────────────────────────

    /**
     * Returns an immutable snapshot of the current item list.
     * Callers cannot accidentally mutate the repository's data.
     */
    fun getItems(): List<String> {
        val snapshot = _items.toList()
        Log.d(TAG, "getItems() → returning ${snapshot.size} item(s)")
        return snapshot
    }

    // ── Write ─────────────────────────────────────────────────────────────

    /**
     * Attempts to add [item] (trimmed) to the list.
     * @return true  → item was added successfully
     *         false → duplicate detected, nothing changed
     */
    fun addItem(item: String): Boolean {
        val trimmed = item.trim()
        return try {
            if (_items.any { it.equals(trimmed, ignoreCase = true) }) {
                Log.w(TAG, "addItem() DUPLICATE → \"$trimmed\" already exists")
                false
            } else {
                _items.add(trimmed)
                Log.d(TAG, "addItem() OK → \"$trimmed\" | total=${_items.size}")
                true
            }
        } catch (e: Exception) {
            Log.e(TAG, "addItem() ERROR for \"$trimmed\"", e)
            false
        }
    }

    /**
     * Removes the exact [item] string from the list.
     * @return true  → item was found and removed
     *         false → item not found
     */
    fun removeItem(item: String): Boolean {
        return try {
            val removed = _items.remove(item)
            if (removed) {
                Log.d(TAG, "removeItem() OK → \"$item\" | remaining=${_items.size}")
            } else {
                Log.w(TAG, "removeItem() NOT FOUND → \"$item\"")
            }
            removed
        } catch (e: Exception) {
            Log.e(TAG, "removeItem() ERROR for \"$item\"", e)
            false
        }
    }

    /**
     * Removes all items from the list.
     * @return the number of items that were cleared
     */
    fun clearItems(): Int {
        return try {
            val count = _items.size
            _items.clear()
            Log.d(TAG, "clearItems() → cleared $count item(s)")
            count
        } catch (e: Exception) {
            Log.e(TAG, "clearItems() ERROR", e)
            0
        }
    }
}

package com.example.kotlinapppractise.viewmodel

import android.util.Log
import androidx.compose.runtime.getValue
import androidx.compose.runtime.mutableStateOf
import androidx.compose.runtime.setValue
import androidx.lifecycle.ViewModel
import com.example.kotlinapppractise.data.ItemRepository

/**
 * ─────────────────────────────────────────────
 *  LAYER 2 — VIEWMODEL  (Business Logic Layer)
 * ─────────────────────────────────────────────
 *
 * The ViewModel sits between the UI and the Repository.
 * Key responsibilities:
 *   • Hold and expose UI state that survives screen rotation
 *   • Validate user input BEFORE sending it to the repository
 *   • Call repository methods and translate results into UI state
 *   • Keep the UI layer completely ignorant of data details
 *
 * ViewModel lifetime:
 *   Created  → when the screen first opens
 *   Survives → screen rotation / configuration changes
 *   Destroyed→ when the screen is permanently removed from back-stack
 *
 * This is why heavy objects (repositories, network clients) live here,
 * not in a Composable function which recomposes frequently.
 */

// ── UI State Data Class ───────────────────────────────────────────────────
/**
 * A single data class that represents everything the UI needs to render.
 * Using a data class makes it easy to reason about the full state at once.
 */
data class MainUiState(
    val items: List<String>       = emptyList(),   // all items in repository
    val displayedList: List<String> = emptyList(), // filtered + sorted subset
    val inputText: String         = "",            // current text-field value
    val searchQuery: String       = "",            // current search text
    val isSorted: Boolean         = false,         // sort toggle
    val errorMessage: String?     = null           // null = no error
)

// ── ViewModel ────────────────────────────────────────────────────────────
class MainViewModel : ViewModel() {

    companion object {
        private const val TAG          = "MainViewModel"
        private const val MAX_LENGTH   = 50          // same limit as before
    }

    // Repository instance — the ViewModel owns it.
    // In a production app, this would be injected via Hilt/Koin.
    private val repository = ItemRepository()

    // Compose-observable state — any Composable that reads `uiState`
    // will automatically recompose when the value changes.
    var uiState by mutableStateOf(MainUiState())
        private set    // UI can READ, only ViewModel can WRITE

    init {
        Log.d(TAG, "ViewModel created — init block running")
        refreshDisplayedList()   // initialise the derived list
    }

    // ── Input field ──────────────────────────────────────────────────────

    /** Called every time the user types in the main text field. */
    fun onInputChanged(text: String) {
        try {
            if (text.length <= MAX_LENGTH) {
                uiState = uiState.copy(inputText = text, errorMessage = null)
                Log.d(TAG, "onInputChanged: length=${text.length}/$MAX_LENGTH")
            } else {
                uiState = uiState.copy(errorMessage = "Maximum $MAX_LENGTH characters allowed")
                Log.w(TAG, "onInputChanged: exceeds limit ${text.length}/$MAX_LENGTH")
            }
        } catch (e: Exception) {
            Log.e(TAG, "onInputChanged ERROR", e)
        }
    }

    // ── Add item ─────────────────────────────────────────────────────────

    /** Validates input then delegates to the repository. */
    fun addItem() {
        try {
            val text = uiState.inputText.trim()
            when {
                text.isBlank() -> {
                    uiState = uiState.copy(errorMessage = "Input cannot be empty")
                    Log.w(TAG, "addItem: blank input rejected")
                }
                text.length > MAX_LENGTH -> {
                    uiState = uiState.copy(errorMessage = "Maximum $MAX_LENGTH characters allowed")
                    Log.w(TAG, "addItem: input too long (${text.length})")
                }
                else -> {
                    val added = repository.addItem(text)
                    if (added) {
                        Log.d(TAG, "addItem: \"$text\" accepted by repository")
                        uiState = uiState.copy(inputText = "", errorMessage = null)
                        refreshDisplayedList()
                    } else {
                        uiState = uiState.copy(errorMessage = "\"$text\" already exists in the list")
                        Log.w(TAG, "addItem: duplicate \"$text\" rejected by repository")
                    }
                }
            }
        } catch (e: Exception) {
            Log.e(TAG, "addItem ERROR", e)
        }
    }

    // ── Remove item ───────────────────────────────────────────────────────

    fun removeItem(item: String) {
        try {
            val removed = repository.removeItem(item)
            if (removed) {
                Log.d(TAG, "removeItem: \"$item\" removed")
                refreshDisplayedList()
            } else {
                Log.w(TAG, "removeItem: \"$item\" not found in repository")
            }
        } catch (e: Exception) {
            Log.e(TAG, "removeItem ERROR for \"$item\"", e)
        }
    }

    // ── Clear all ─────────────────────────────────────────────────────────

    fun clearItems() {
        try {
            val count = repository.clearItems()
            Log.d(TAG, "clearItems: $count item(s) cleared")
            uiState = uiState.copy(searchQuery = "")
            refreshDisplayedList()
        } catch (e: Exception) {
            Log.e(TAG, "clearItems ERROR", e)
        }
    }

    // ── Search ────────────────────────────────────────────────────────────

    fun onSearchChanged(query: String) {
        try {
            uiState = uiState.copy(searchQuery = query)
            Log.d(TAG, "onSearchChanged: \"$query\"")
            refreshDisplayedList()
        } catch (e: Exception) {
            Log.e(TAG, "onSearchChanged ERROR", e)
        }
    }

    // ── Sort ──────────────────────────────────────────────────────────────

    fun toggleSort() {
        try {
            val newSorted = !uiState.isSorted
            uiState = uiState.copy(isSorted = newSorted)
            Log.d(TAG, "toggleSort: isSorted=$newSorted")
            refreshDisplayedList()
        } catch (e: Exception) {
            Log.e(TAG, "toggleSort ERROR", e)
        }
    }

    // ── Private helpers ───────────────────────────────────────────────────

    /**
     * Re-fetches the item list from the repository, applies the active
     * search filter and sort preference, then updates [uiState].
     *
     * Call this after every operation that changes repository data
     * or filter/sort settings.
     */
    private fun refreshDisplayedList() {
        try {
            val all = repository.getItems()
            val query = uiState.searchQuery
            val sorted = uiState.isSorted

            val filtered = if (query.isBlank()) all
                           else all.filter { it.contains(query, ignoreCase = true) }

            val displayed = if (sorted) filtered.sorted() else filtered

            uiState = uiState.copy(items = all, displayedList = displayed)

            Log.d(
                TAG,
                "refreshDisplayedList: total=${all.size}, shown=${displayed.size}, " +
                "sorted=$sorted, query=\"$query\""
            )
        } catch (e: Exception) {
            Log.e(TAG, "refreshDisplayedList ERROR", e)
        }
    }

    // ── ViewModel lifecycle ────────────────────────────────────────────────

    /**
     * onCleared() is called by Android right before the ViewModel is destroyed.
     * Use it to cancel coroutines, close streams, release resources, etc.
     */
    override fun onCleared() {
        super.onCleared()
        Log.d(TAG, "onCleared — ViewModel is being destroyed")
    }
}

